import React from 'react';
import './RecentActivity.css';

const activities = [
  { type: 'order', user: 'Sarah K.', action: 'placed a new order', amount: '$340', time: '2m ago', color: '#7c6af7', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
  { type: 'signup', user: 'Marcus T.', action: 'created an account', amount: null, time: '8m ago', color: '#22d3ee', icon: 'M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z' },
  { type: 'payment', user: 'Lena R.', action: 'completed payment', amount: '$1,200', time: '15m ago', color: '#34d399', icon: 'M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z' },
  { type: 'refund', user: 'James W.', action: 'requested a refund', amount: '$89', time: '34m ago', color: '#f87171', icon: 'M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6' },
  { type: 'order', user: 'Priya M.', action: 'placed a new order', amount: '$520', time: '1h ago', color: '#7c6af7', icon: 'M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z' },
  { type: 'upgrade', user: 'Chen L.', action: 'upgraded to Pro plan', amount: '$99/mo', time: '2h ago', color: '#f97316', icon: 'M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z' },
];

export default function RecentActivity() {
  return (
    <div className="card activity-card">
      <div className="activity-header">
        <div className="card-title">Recent Activity</div>
        <button className="view-all-btn">View all</button>
      </div>
      <div className="activity-list">
        {activities.map((a, i) => (
          <div className="activity-item" key={i}>
            <div className="activity-icon" style={{ '--ic': a.color }}>
              <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.8}>
                <path strokeLinecap="round" strokeLinejoin="round" d={a.icon} />
              </svg>
            </div>
            <div className="activity-body">
              <div className="activity-text">
                <span className="activity-user">{a.user}</span>
                <span className="activity-action"> {a.action}</span>
              </div>
              <div className="activity-time">{a.time}</div>
            </div>
            {a.amount && <div className="activity-amount" style={{ color: a.type === 'refund' ? 'var(--danger)' : 'var(--success)' }}>{a.type === 'refund' ? '-' : '+'}{a.amount}</div>}
          </div>
        ))}
      </div>
    </div>
  );
}
